import json
from datetime import datetime

with open(locals()['var_function-call-9297306959250454067'], 'r') as f:
    reviews = json.load(f)

businesses = locals()['var_function-call-15901127623642277084']

def is_2018(date_str):
    formats = [
        "%B %d, %Y at %I:%M %p",
        "%d %B %Y, %H:%M",
        "%Y-%m-%d %H:%M:%S",
        "%d %b %Y, %H:%M"
    ]
    for fmt in formats:
        try:
            dt = datetime.strptime(date_str, fmt)
            if dt.year == 2018:
                return True
            return False
        except ValueError:
            continue
    return False

reviewed_2018_refs = set()
for r in reviews:
    if is_2018(r['date']):
        reviewed_2018_refs.add(r['business_ref'])

print(f"DEBUG: Unique business_refs reviewed in 2018: {len(reviewed_2018_refs)}")

reviewed_ids = set()
for ref in reviewed_2018_refs:
    if ref.startswith('businessref_'):
        bid = 'businessid_' + ref.split('_')[1]
        reviewed_ids.add(bid)

matching_businesses = []
for b in businesses:
    bid = b.get('business_id')
    if bid in reviewed_ids:
        attrs = b.get('attributes')
        matching_businesses.append({'bid': bid, 'attrs': attrs})

print(f"DEBUG: Businesses found in DB: {len(matching_businesses)}")

final_count = 0
for b in matching_businesses:
    attrs = b['attrs']
    if not attrs or attrs == "None":
        continue

    has_bike = attrs.get('BikeParking') == 'True'
    has_biz_park = False
    bp_str = attrs.get('BusinessParking')
    if bp_str and bp_str != 'None':
        try:
            bp_dict = eval(bp_str)
            if isinstance(bp_dict, dict):
                if any(v is True for v in bp_dict.values()):
                    has_biz_park = True
        except:
            pass

    if has_bike or has_biz_park:
        final_count += 1
        # print(f"DEBUG: Match: {b['bid']}, Bike: {has_bike}, Car: {has_biz_park}")

print("__RESULT__:")
print(json.dumps(final_count))

